    ["", "یکصد", "دویست", "سیصد", "چهارصد", "پانصد", "ششصد", "هفتصد", "هشتصد", "نهصد"];

// Pre-computed group divisors and suffixes — avoids per-call Dictionary and Math.Pow allocations
private static readonly (long divisor, string suffix)[] FarsiGroups =
[
    (1_000_000_000_000_000, "کوادریلیون"),
    (1_000_000_000_000, "تریلیون"),
    (1_000_000_000, "میلیارد"),
    (1_000_000, "میلیون"),
    (1_000, "هزار"),
];

/// <inheritdoc />
public string Convert(long number)
{
    if (number == 0)
    {
        return FarsiOnesMap[0];
    }

    if (number < 0)
    {
        return $"منفی {Convert(-number)}";
    }

    var parts = new List<string>(4);

    foreach (var (divisor, suffix) in FarsiGroups)
    {
        if (number / divisor > 0)
        {
            parts.Add($"{Convert(number / divisor)} {suffix}");
            number %= divisor;
        }
    }

    if (number / 100 > 0)
    {
        parts.Add(FarsiHundredsMap[number / 100]);
        number %= 100;
    }

