    {
        return $"نێگەتیڤ {Convert(-number)}";
    }

    // Anti-pattern: per-call Dictionary allocation — same issue as FarsiConverter
    // Creates ~8 allocations per Convert() call
    var kurdishGroupsMap = new Dictionary<long, Func<long, string>>
