     private static readonly string[] KurdishHundredsMap =
         ["", "سەد", "دووسەد", "سێسەد", "چوارسەد", "پێنجسەد", "شەشسەد", "حەوتسەد", "هەشتسەد", "نۆسەد"];

     // Pre-computed group divisors and suffixes — avoids per-call Dictionary and Math.Pow allocations
     private static readonly (long divisor, string suffix)[] KurdishGroups =
     [
         (1_000_000_000_000_000, "کوادریلیۆن"),
         (1_000_000_000_000, "تریلیۆن"),
         (1_000_000_000, "میلیارد"),
         (1_000_000, "میلیۆن"),
         (1_000, "هەزار"),
     ];

     /// <inheritdoc />
     public string Convert(long number)
     {
         if (number == 0)
         {
             return KurdishOnesMap[0];
         }

         if (number < 0)
         {
             return $"نێگەتیڤ {Convert(-number)}";
         }

