                 number %= divisor;
             }
         }

         if (number / 100 > 0)
         {
             parts.Add(KurdishHundredsMap[number / 100]);
             number %= 100;
         }

         if (number >= 10)
         {
             parts.Add(KurdishTensMap[number / 10]);
             number %= 10;
         }

         if (number > 0)
